import React from 'react';
import { Link } from 'react-router-dom';

function Home() {
  return (
    <div className="container">
      <h1>Naryn Clinic Queue System</h1>
      <Link to="/patient">
        <button>Patient Registration</button>
      </Link>
      <Link to="/login">
        <button>Doctor Login</button>
      </Link>
    </div>
  );
}

export default Home;
